```python
from social.backends import facebook
from requests.exceptions import HTTPError
from requests.models import Response
from rest_framework.test import APITestCase

def get_facebook_info_mock(self, access_token, *args, **kwargs):
    info = {
        'user_1': {
            'id': '00001',
            'name': 'Foo Bar',
            'email': 'foo@bar.com',
        },
        # ...
    }
    try:
        return info[access_token]
    except KeyError:
        response = Response()
        response.status_code = 400
        raise HTTPError('Error', response=response)


class FacebookTestCase(APITestCase):
    def setUp(self):
        facebook.FacebookOAuth2.user_data = get_facebook_info_mock

    def testFacebook(self):
       d = {'grant_type': 'convert_token', 'client_id': 'foo', 'client_secret': 'bar', 'backend': 'facebook', 'token': 'user_1'}
        response = self.client.post('/oauth/convert-token/', d)
        self.assertEqual(response.status_code, 200, response.data)
        user = User.objects.all().latest('date_joined')
        self.assertEqual(user.email, "foo@bar.com")
```

if the empty ``{{ recoverlist_url }}`` issue is correct, there might be a similar issue in the breadcrumbs:

````
{% block breadcrumbs %}
    {% if not is_popup %}
        <ul>
            <li><a href="{% url 'admin:index' %}">{% trans "Home" %}</a></li>
            <li><a href="{% url 'admin:app_list' app_label %}">{% trans app_label|capfirst|escape %}</a></li>
            <li><a href="{{ changelist_url }}">{% trans opts.verbose_name_plural|capfirst %}</a></li>
            <li><a href="{{ change_url }}">{{ original|truncatewords:"18" }}</a></li>
            <li><a href="../">{% trans "History" %}</a></li>
            <li>{% blocktrans with opts.verbose_name as verbose_name %}Revert {{ verbose_name }}{% endblocktrans %}</li>
        </ul>
    {% endif %}
{% endblock %}
```

In this case the empty vars are `{{ changelist_url }}` and `{{ change_url }}`.

